  ('pukao-1fb53453-moex-00098', 'pukao-1fb53453', 'pukao-1fb53453-moex-113-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '甲之外籍配偶乙向我國駐外使領館申請入臺簽證，但經調查甲、乙婚姻真實性尚有可疑之處，乃拒絕 核發簽證。依憲法法庭裁判意旨，下列敘述何者正確？', '["因入臺簽證僅外國人須申請，甲非申請人故無提起行政救濟之權利", "甲與乙僅具有事實上或情感上之利害關係，故甲不得提起行政救濟", "基於維護婚姻與家庭關係，甲得提起課予義務訴訟尋求救濟", "因配偶經營共同生活之婚姻自由受侵害，甲得對該拒絕處分提起撤銷訴訟尋求救濟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
