  ('pukao-1fb53453-moex-00101', 'pukao-1fb53453', 'pukao-1fb53453-moex-113-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '關於國家賠償法所規定之公務員國家賠償責任，下列敘述何者正確？', '["給付行政措施，不生公務員國家賠償責任", "受委託行使公權力者，於行使公權力時，亦適用公務員國家賠償責任", "為求人民權利保障之完整性，縱使公務員並無故意或過失，亦構成公務員國家賠償責任", "為使人民權利獲得全面性之保障，故公務員之不法行為與損害發生間，不以具有因果關係為必要"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
